import React, { useCallback, useEffect, useRef, useState } from 'react';
import { useLocation, useNavigate, useParams } from 'react-router-dom';
import HeaderTopBar from '../common/HeaderTopBar/HeaderTopBar';
import { Eyeglass, arrowRight, taskIcon, tasks } from '../../assets/images/icons';
import Button from '../common/UI/Button/Button';
import TaskBoardPanel from '../common/TaskBoardPanel/TaskBoardPanel';
import TaskCard from './TaskComps/TaskCard/TaskCard';
import TaskModal from './TaskComps/TaskModal/TaskModal';
import { updateTask, getAllCompletedTasks, getAllTasks, getTaskById } from '../../services/tasks.service';
import { setSelectedProcess, setProcessModule, setMessageBar, setShowMenu, resetFlowReducer, setShowSideMenu } from '../../reduxStore/actions/flowActions';
import cls from './Dashboard.module.scss';
import { getCompanyProcesses, getProcessById } from '../../services/processes.service';
import { addNewFieldToComponent, getAllFavorites, updateComponent } from '../../services/components.service';
import { getTransactions } from '../../services/transactions.service';
import { getProducts } from '../../services/products.service';
import { APPEND_TO_DATA, CLEAR_TO_SET_DATA, computeFormula, getDateForm, dashboard_page_default, page_default, priorityArray, FORCED, pagination, no_pagination, pagination_max, APP_NAME } from '../../shared/utility';
import { store } from '../../reduxStore/store';
import { first, take } from 'rxjs/operators';
import { getAlComponentsByModuleId, getAllModules } from '../../services/module.service';
import { Tab, Tabs, TabList, TabPanel } from 'react-tabs';
import { createNewCompany, getCompanyDetails } from '../../services/company.service';
import ModulePanel from '../../components/SideMenuEntries/ModulesComp/ModulePanel';
import ComponentModuleCard from '../../components/SideMenuEntries/ModulesComp/ComponentModuleCard';
import { RenderComponentDetailView } from './ModulesComp/ModuleStep';
import { FieldRow, ModalR, RenderYesNoSwitcher, SelectD } from '../common';
import { useProcessTaskContext, processTaskAction } from '../../context/processTask.context';

import { isMobile } from 'react-device-detect';
import { connect, useDispatch, useSelector } from 'react-redux';
import moment, { now } from 'moment';
import 'react-tabs/style/react-tabs.css';
import ReactToPrint from 'react-to-print';
import MessageContainer from './ProcessesComps/MessageContainer/MessageContainer';
import InfoTaskModal from './TaskComps/InfoTaskModal/InfoTaskModal';
import { resetAuthReducer } from '../../reduxStore/actions/authActions';
import { geminiAI } from '../../services/search.service';
import { faRetweet } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';

const R = require('ramda');

const Dashboard = props => {
	const location = useLocation();
	const { allTasks, allCompletedTasks, allCompletedTasksPaginated, onSetSelectedProcess, user, companyProcesses, allModules, components, companyData, companyUsersArray, begunModule, blueprints } = props;
	const [loading, setLoading] = useState(false);
	const [taskModalVisible, setTaskModalVisible] = useState(false);
	const [isEditTask, setIsEditTask] = useState(false);
	const [page, setPage] = useState(1);
	const [cmpPage, setCmpPage] = useState(1);
	const [renderTasks, setRenderTasks] = useState({ laterTasks: [], todayTasks: [], overdueTasks: [], completedTasks: [] });
	const [, setRenderCompletedTasks] = useState([]);
	const [taskToEdit, setTaskToEdit] = useState('');
	const [tabIndex, setTabIndex] = useState(0);
	const [openDetailView, setOpenDetailView] = useState(false);
	const [selectedComponent, setSelectedComponent] = useState({});
	const [, setTaskProcessContext] = useProcessTaskContext();
	const [forPrinting, setForPrinting] = useState(false);
	const [newCompany, setNewCompany] = useState({ message: '' });
	const [showTask, setShowTask] = useState(false);
	const { hash, transactionID, newStatus } = useParams();
	const [searchQuery, setSearchQuery] = useState('');
	const [searchModule, setSearchModule] = useState();
	const [aiResponse, setAIResponse] = useState({ candidates: [] });
	const [showInfo, setShowInfo] = useState((allModules?.length == 0 || companyProcesses.length == 0) ? localStorage.getItem('showInfo') === 'false' ? false : true : false);

	const dispatch = useDispatch();
	const navigate = useNavigate();

	let componentRef = useRef();
	let cnt = 0;

	const { authenticated } = useSelector(store => store.sessionReducer);

	document.title = `Dashboard | ${APP_NAME}`;

	useEffect(() => {
		dispatch(setShowSideMenu(true));
		dispatch(setShowMenu(true));
	}, []);

	useEffect(() => {
		if (authenticated) {
			if (!(companyData?.status === 'trial_ended' || companyData?.status === 'inactive')) {
				getAllTasks(user.id)
					.pipe(take(1))
					.subscribe({
						complete: () => getAllCompletedTasks(CLEAR_TO_SET_DATA, user.id).pipe(take(1)).subscribe({}),
					});
				
				user?.pinned_modules?.map(
					pinned_module =>
						components.filter(com => com.module_id === pinned_module.id).length == 0 &&
						getAlComponentsByModuleId(pinned_module, APPEND_TO_DATA, pagination_max, 1, true)
							.pipe(take(1))
							.subscribe({
								next: (data) => {
									pinned_module.lastUpdate = 0;
									pinned_module.count = data?.total ?? 0;
								},
							})
				);

				companyProcesses.length == 0 &&
					store.dispatch(setMessageBar({ show: true, message: isMobile ? `Fetching data...` : `Fetching workflows and transactions. Dashboard will update in a while...`, color: 'var(--app-color-gray-light)', spinner: true, noTimeout: true, bottom: true }));

				getAllFavorites().pipe(take(1)).subscribe({
					next: () => {
						getTransactions(CLEAR_TO_SET_DATA)
							.pipe(take(1))
							.subscribe({
								complete: () =>
									getProducts(CLEAR_TO_SET_DATA)
										.pipe(take(1))
										.subscribe({}),
							});
					}
				});

				if (hash?.length > 0) {
					getTaskById(hash)
						.pipe(take(1))
						.subscribe({
							next: data => {
								setTaskToEdit(data);
								setShowTask(true);
							},
						});
				} else if (transactionID?.length > 0) {
					setSelectedComponent(components?.find(c => c.id === transactionID));

					const process = companyProcesses?.find(proc => proc.id === allModules.find(m => m.id === components.find(c => c.id === transactionID).module_id)?.procedure?.id);
					if (process?.steps?.length > 0) {
						store.dispatch(setProcessModule(process));

						setLoading(false);

						if (newStatus?.length > 0) {
							goToTransaction(
								process,
								components.find(c => c.id === transactionID),
								newStatus
							);
						} else {
							setOpenDetailView(true);
						}
					} else {
						setLoading(true);
						getProcessById(process.id)
							.pipe(first())
							.subscribe({
								next: data => {
									store.dispatch(setProcessModule(data));
									setLoading(false);
									if (newStatus?.length > 0) {
										goToTransaction(
											data,
											components.find(c => c.id === transactionID)
										);
									} else {
										setOpenDetailView(true);
									}
								},
								error: _error => { },
							});
					}
				}
			}
			if (user?.id === '') {
				dispatch(resetAuthReducer());
				dispatch(resetFlowReducer());
			}
		}
	}, [authenticated]);

	useEffect(() => {
		allModules.length > 0 &&
			allModules.filter((module, index) =>
				getAlComponentsByModuleId(module, APPEND_TO_DATA, pagination_max, 1)
					.pipe(take(1))
					.subscribe({
						next: data => {
							cnt = cnt + 1;
							if (cnt == allModules.length) {
								store.dispatch(setMessageBar({ show: false, message: '' }));
							}

							module.lastUpdate = now();
							//module.count = data?.total ?? 0;
						},
					})
			);
	}, [allModules]);

	useEffect(() => {
		const item = allTasks?.find(i => i.id == new URLSearchParams(location?.search).get('taskId'));
		if (item) {
			setTaskToEdit(item);
			setTaskModalVisible(true);
		}
	}, [allTasks, location]);

	const postQuery = useCallback((query, module) => {
		if (query.length == 0) {
			setAIResponse({ candidates: [{ content: { parts: [{ text: 'Enter a question that I could answer' }] } }] });
			return;
		}

		let analyze = {
			role: 'user',
			parts: [{ text: query }],
		};

		if (module) {
			analyze.parts = [
				...analyze.parts,
				{
					text: JSON.stringify({
						table: module.module.name,
						data: components
							.filter(com => com.module_id === module.value)
							.map(com => {
								let details = {};
								com.component_fields.filter(cf => (details = { ...details, [cf.field_name]: cf.value }));
								return {
									...details,
									created_date: com.created_date,
									created_by: com.created_by.id,
									items: com?.component_items.map(it => {
										return {
											item: it.item_code,
											quantity: +it.quantity,
											value: it.value,
										};
									}),
								};
							}),
					}),
				},
			];
		}
		setLoading(true);
		geminiAI(JSON.stringify(analyze))
			.pipe(first())
			.subscribe({
				next: data => {
					setLoading(false);
					setAIResponse(data);
				},
				error: error => {
					setAIResponse({ candidates: [{ content: { parts: [{ text: JSON.stringify(error) }] } }] });
					setLoading(false);
				},
			});
	}, []);

	const aiResults =
		aiResponse?.candidates?.length > 0 &&
		aiResponse?.candidates.map(can => {
			return can.content?.parts?.map((part, index) => {
				return <textarea className={cls.searchResults} disabled key={100 + index} value={part.text} />;
			});
		});

	const searchButton = () => (
		<div style={{ display: 'flex', verticalAlign: 'center' }}>
			<div className={cls.searchContainer}>
				<input
					placeholder="How can we help you today?"
					className={cls.searchInput}
					onChange={val => {
						setSearchQuery(val.target.value);
					}}
					value={searchQuery}
				/>

				<SelectD
					items={allModules.map(elem => {
						return { label: elem.name, value: elem.id, module: elem };
					})}
					defaultSelected={'Orders'}
					className={cls.dropdownSelectComponent}
					tmiClassName={cls.dropdownInput}
					molclassname={cls.dropdownSelectMenuOverlayList}
					moliclassname={cls.dropdownSelectMenuOverlayListItem}
					onChange={selection => {
						setSearchModule(selection);
					}}
				/>
				<Button clear clicked={() => postQuery(searchQuery, searchModule)} loading={loading} loaderRadius={'30'}>
					{!loading && <Eyeglass />}
				</Button>
			</div>
		</div>
	);
	const setCompletedTasks = useCallback(() => {
		const completed = [];
		if (allCompletedTasksPaginated?.length === 0) return;
		allCompletedTasksPaginated.map(elem => {
			return completed.push({
				taskName: elem.name,
				process: elem?.process?.name,
				completedOn: moment(elem.completed_at).format('DD MMMM YYYY hh:mm'),
				duration: elem.duration,
			});
		});
		setRenderCompletedTasks(completed);

		setRenderTasks({ ...renderTasks, completedTasks: allCompletedTasksPaginated });
	}, [allCompletedTasks, allTasks]);

	useEffect(() => setCompletedTasks(), [allCompletedTasks, allTasks]);
	useEffect(() => setTaskArray(), [allTasks]);
	useEffect(
		() =>
			onSetSelectedProcess({
				description: '',
				id: '',
				is_pinned: '',
				name: '',
				user_id: '',
				registered: false,
				type: false,
			}),
		[]
	);

	const setTaskArray = useCallback(() => {
		const overdue = [],
			today = [],
			later = [];
		if (allTasks?.length === 0) return;
		allTasks.map(e => {
			const todayDate = moment(new Date()).format('YYYY-MM-DD');
			if (e.status === 'Done') {
				return;
			} else if (moment(e.due_date, 'YYYY-MM-DD').isSame(todayDate)) {
				return today.push(e);
			} else if (e.status === 'Moved' || e.status === 'Postponed' || e.status === 'Cancelled') {
				return later.push(e);
			} else if (moment(e.due_date, 'YYYY-MM-DD').isAfter(todayDate)) {
				return later.push(e);
			} else {
				return overdue.push(e);
			}
		});
		const renderObjects = { laterTasks: later, todayTasks: today, overdueTasks: overdue, completedTasks: allCompletedTasksPaginated };
		setRenderTasks(renderObjects);
	}, [allTasks]);

	const goToTransaction = (process, component, status = undefined) => {
		let component_array = [];
		let step_no = 1;

		process?.steps?.length > 0 && process?.steps?.filter(step => step?.component_blueprints?.filter(cb => cb.selected_fields.filter(field => (field.value = undefined))));
		R.uniqWith(R.eqProps('group'))(component.component_fields).map(f => {
			component_array = [...component_array, { id: f.component_blueprint_id, temp_id: f.id, selected_fields: R.filter(R.propEq('group', f.group))(component.component_fields) }];
		});

		process.steps.filter(step => {
			step.component_blueprints.filter(cb => {
				cb.selected_fields.filter(sf => {
					const field_found = component.component_fields.find(cf => cf.field_name === sf.field_name);
					if (sf.data_type_name === 'Status' && status !== undefined) {
						step_no = +step.rank - 1;
					}

					if (field_found != undefined) {
						sf.value = field_found.value;
					} else if (sf.data_type_name === 'Record') {
						const label_found = component.component_fields.find(cf => cf.field_name === sf.options.name);
						if (label_found != undefined) {
							sf.value = label_found.value;
						}
					}
				});
			});
		});

		setTaskProcessContext({
			action: processTaskAction.setComponents,
			value: component_array,
		});
		setTaskProcessContext({
			action: processTaskAction.setModuleItems,
			value: component.component_items,
		});

		store.dispatch(
			setProcessModule({
				...process,
				steps: process.steps,
				stepIndex: step_no,
				module_id: component.module_id,
				module: allModules.find(mod => mod.id === component.module_id),
				isUpdating: true,
				selectedComponent: component,
			})
		);
		store.dispatch(setShowMenu(false));
		navigate('/begin-module');
	};

	const newTaskOpen = () => {
		setTaskModalVisible(!taskModalVisible);
	};

	const editTaskOpen = () => {
		setTaskModalVisible(true);
		setIsEditTask(true);
	};

	const editTaskClose = () => {
		setTaskModalVisible(false);
		setIsEditTask(false);
	};

	const resumeTask = task => {
		updateTask({ status: 'Done' }, task?.id).subscribe({
			next: data => {
				allCompletedTasksPaginated.push(data);
			},
			complete: () => setTabIndex(3),
		});
	};
	const createCompany = () => {
		if (newCompany.companyName && newCompany.displayName && newCompany.email && newCompany.firstName && newCompany.lastName && newCompany.slug) {
			setLoading(true);
			createNewCompany(newCompany)
				.pipe(take(1))
				.subscribe({
					next: () => store.dispatch(setMessageBar({ show: true, message: `Success! ${newCompany.companyName} was created. Email notification sent to ${newCompany.email}` })),
					complete: () => setLoading(false),
				});
		}
	};
	const renderSuperAdminCreateCompany = () => {
		return (
			<div>
				<FieldRow fieldLabel={'Company Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, companyName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Company Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Display Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, displayName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Company Name'}
						/>
					</div>
				</FieldRow>

				<FieldRow fieldLabel={'Slug'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, slug: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Slug'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Email'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, email: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Email'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'First Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, firstName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'First Name'}
						/>
					</div>
				</FieldRow>
				<FieldRow fieldLabel={'Last Name'} style={{ border: '0' }} visible={true}>
					<div className={cls.fieldRowContainer}>
						<input
							onChange={e => {
								setNewCompany({ ...newCompany, lastName: e.target.value });
							}}
							autoComplete="none"
							className={cls.fieldTypeInput}
							name={'Last Name'}
						/>
					</div>
				</FieldRow>
			</div>
		);
	};

	const renderProcessDashboardFunction = () => {
		let fields_to_display = [];

		allModules.filter(mod =>
			companyProcesses
				.filter(proc => mod.procedure.id === proc.id && proc.steps.length > 0 && proc?.steps?.filter(step => step.component_blueprints.filter(cb => cb.options?.asDashboard == true)))
				.filter(proc =>
					proc.steps
						.filter(st => st.component_blueprints.filter(cb => cb.options?.asDashboard == true))
						.filter(s =>
							s.component_blueprints
								.filter(c => c.options?.asDashboard == true)
								.filter(cbp =>
									cbp.selected_fields
										.filter(sf => sf.visible == true && sf.data_type_name === 'Formula')
										.map(sf => {
											if (user?.positions?.filter(pos => cbp.options?.showOnly?.includes(pos.id)).length > 0 || cbp.options?.showOnly?.length == 0 || cbp.options?.showOnly === undefined) {
												fields_to_display = [...fields_to_display, { ...sf, module_id: mod.id, procedure: proc, module: mod }];
											} else {
												fields_to_display = [...fields_to_display];
											}
										})
								)
						)
				)
		);

		if (fields_to_display.length > 0) {
			if (isMobile == true) {
				fields_to_display = fields_to_display.slice(0, 2)
			}
			return (
				<div style={{ display: 'flex', margin: '20px 20px 30px 0' }}>
					{fields_to_display.map((f, i) => {
						let value = f.value ?? 0;
						if (f.data_type_name === 'Formula') {
							value = computeFormula(f.options, components, [], []);
						}

						return components.filter(c => c.module_id === f.module_id).length > 0 ? (
							<div
								key={i}
								className={cls.dashboardCard}
								onClick={() => {
									store.dispatch(setShowMenu(false));
									store.dispatch(
										setProcessModule({
											...f.procedure,
											stepIndex: 0,
											module_id: f.module_id,
											module: f.module,
										})
									);

									if (f?.options?.operator === 'countdateocc') {
										navigate(`/modules/${f.module_id}?key=${f.options.list.length > 0 ? f.options.list[0] : 'Status'}&value=${moment(getDateForm(f?.options?.searchtext)).format('DD MMM YYYY')}`);
									} else {
										navigate(`/modules/${f.module_id}?key=${f.options.list.length > 0 ? f.options.list[0] : 'Status'}&value=${f.options.searchtext ?? ''}`);
									}
								}}
							>
								<p>{f.field_name}</p>
								{value}
							</div>
						) : (
							i == 0 && <div key={i} />
						);
					})}
				</div>
			);
		}
	};

	const renderModulesFunction = module => {

		const array_to_display = components.filter(com => com.module_id === module.id);
		let count = Math.ceil(  (module?.count ? +module?.count : array_to_display.length) / dashboard_page_default);

		if (isMobile && count > 7) {
			count = 7;
		} else if (!isMobile && count > 23) {
			count = 23;
		}

		const array =
			array_to_display.length > 0
				? (array_to_display.length < dashboard_page_default + 1 || cmpPage == 123456)
					? R.sortWith([R.descend(R.prop('created_date'))])(array_to_display)
					: R.sortWith([R.descend(R.prop('created_date'))])(array_to_display).slice(cmpPage * dashboard_page_default - dashboard_page_default, cmpPage * dashboard_page_default)
				: [];

		return (
			<div>
				{array_to_display.length > 0
					? array.map((component, index) => {
						return (
							<div key={index}>
								<ComponentModuleCard
									isEditable={false}
									options={module?.options}
									component={component}
									clicked={() => {
										setSelectedComponent(component);
										companyData.start = true;

										if (companyProcesses.length > 0 && companyProcesses.find(proc => proc.id === module.procedure.id)?.steps.length > 0) {
											store.dispatch(setProcessModule(companyProcesses.find(proc => proc.id === module.procedure.id)));
											setOpenDetailView(true);
											return;
										}
										setLoading(true);
										getProcessById(module.procedure.id)
											.pipe(first())
											.subscribe({
												next: data => {
													store.dispatch(setProcessModule(data));
													setOpenDetailView(true);
													setLoading(false);
												},
												error: _error => { },
											});
									}}
									setComponentToEdit={() => { }}
									openModal={() => { }}
								/>
							</div>
						);
					})
					: 'No items found'}
				<div style={{ display: count > 1 ? 'flex' : 'none', margin: '20px 0 0 0' }}>
					{array_to_display.length > 0 && (
						<>
							<p style={{ padding: '0 10px 0 0', fontSize: '14px' }}>Page:</p>
							{count > 0 && [...Array(count)].map((obj, index) => <Button title={index + 1} disabled={index == cmpPage - 1 ? true : false} clear key={index} style={{ maxWidth: '34px', minWidth: '20px', display: index < 16 ? '' : 'none', padding: '0' }} titleContainer={cls.pageContainer}
								clicked={() => {

									const actual_page = Math.ceil(array_to_display.length / dashboard_page_default);
									const next_page = (index + 1);

									if (next_page >= actual_page) {

										setLoading(true);

										getAlComponentsByModuleId(module, APPEND_TO_DATA, (next_page - actual_page) <= 1 ? dashboard_page_default : (dashboard_page_default * next_page), (next_page - actual_page) <= 1 ? next_page : 1)
											.pipe(take(1))
											.subscribe({
												next: (data) => {
													setLoading(false);
													module.lastUpdate = 0;
													module.count = data?.total ?? 0;
													setCmpPage(next_page);
												},
											})

										if (next_page == actual_page) {
											setCmpPage(next_page);
										}

									} else {
										setCmpPage(next_page);
									}

								}
								} />)}
						</>
					)}
					<Button title={'All'} disabled={cmpPage == 123456 ? true : false} clicked={() => {
						getAlComponentsByModuleId(module, APPEND_TO_DATA, 999999, 1)
							.pipe(take(1))
							.subscribe({
								next: (data) => {
									setLoading(false);
									module.lastUpdate = 0;
									module.count = data?.total ?? 0;

								},
							})


						setCmpPage(123456);
					}} clear />
				</div>
			</div>
		);
	};

	const renderTasksFunction = tasks => {
		let count = Math.ceil(tasks.length / page_default);
		if (isMobile && count > 8) {
			count = 7;
		} else if (!isMobile && count > 23) {
			count = 23;
		}
		const array = tasks.length > 0 ? (tasks.length < page_default + 1 || page == 123456 ? R.sortWith([R.ascend(R.prop('due_date'))])(tasks) : R.sortWith([R.ascend(R.prop('due_date'))])(tasks).slice(page * page_default - page_default, page * page_default)) : [];

		return (
			<div>
				<Button style={{ width: '120px', display: 'none' }} clicked={newTaskOpen} title={'New Task'} />
				{tasks.length > 0
					? array.map((task, index) => {
						return (
							<div key={index}>
								<TaskCard
									isEditable
									task={task}
									clicked={() => {
										resumeTask(task);
									}}
									taskId={task.id}
									setTaskToEdit={() => setTaskToEdit(task)}
									openModal={() => editTaskOpen()}
									priority={task?.add_info?.priority !== null ? priorityArray.find(p => p.value === task?.add_info?.priority)?.icon : ''}
								/>
							</div>
						);
					})
					: 'No tasks found'}
				{tasks.length > 0 && (
					<div style={{ display: count > 1 ? 'flex' : 'none', margin: '20px 0 0 0' }}>
						<p style={{ padding: '0 10px 0 0', fontSize: '14px' }}>Page:</p>
						{count > 0 && [...Array(count)].map((obj, index) => <Button title={index + 1} titleContainer={cls.pageContainer} disabled={index == page - 1 ? true : false} clear key={index} style={{ fontSize: '10px', maxWidth: '34px', minWidth: '20px', padding: '0', display: index < 18 ? '' : 'none' }} clicked={() => setPage(index + 1)} />)}
						<Button title={'All'} disabled={page == 123456 ? true : false} clicked={() => setPage(123456)} clear />
					</div>
				)}
			</div>
		);
	};

	const renderCompletedTasksFunction = tasks => {
		let count = Math.ceil(tasks.length / dashboard_page_default);
		if (isMobile && count > 8) {
			count = 7;
		} else if (!isMobile && count > 23) {
			count = 23;
		}
		const array =
			tasks.length > 0
				? tasks.length < dashboard_page_default - 1 || page == 123456
					? R.sortWith([R.descend(R.prop('completed_at'))])(tasks)
					: R.sortWith([R.descend(R.prop('completed_at'))])(tasks).slice(page * dashboard_page_default - dashboard_page_default, page * dashboard_page_default)
				: [];

		return (
			<div>
				<Button style={{ width: '120px', display: 'none' }} clicked={newTaskOpen} title={'New Task'} />
				<div style={{ fontSize: '12px', textAlign: 'right' }}>{tasks?.length > 0 ? 'Completed Date' : ''}</div>
				{tasks.length > 0
					? array.map((task, index) => {
						return (
							<div key={index}>
								<TaskCard false task={task} clicked={() => { }} taskId={task.id} setTaskToEdit={() => setTaskToEdit(task)} openModal={() => editTaskOpen()} priority={task?.add_info?.priority !== null ? priorityArray.find(p => p.value === task?.add_info?.priority)?.icon : ''} />
							</div>
						);
					})
					: 'No tasks found'}

				{tasks.length > 0 && (
					<div style={{ display: count > 1 ? 'flex' : 'none', margin: '20px 0 0 0' }}>
						<p style={{ padding: '0 10px 0 0', fontSize: '14px' }}>Page:</p>
						{count > 0 && [...Array(count)].map((obj, index) => <Button title={index + 1} titleContainer={cls.pageContainer} disabled={index == page - 1 ? true : false} clear key={index} style={{ fontSize: '10px', maxWidth: '34px', minWidth: '20px', padding: '0', display: index < 18 ? '' : 'none' }} clicked={() => setPage(index + 1)} />)}
						<Button title={'All'} disabled={page == 123456 ? true : false} clicked={() => setPage(123456)} clear />
					</div>
				)}
			</div>
		);
	};

	const status = selectedComponent?.component_fields?.find(cf => cf.data_type_name === 'Status')?.value;
	const authorized =
		begunModule?.processModule?.steps?.length > 0
			? begunModule?.processModule?.steps
				?.find(step => step?.component_blueprints.filter(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Status').length > 0).length > 0)
				?.component_blueprints?.find(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Status').length > 0)?.options?.showOnly
			: undefined;

	//console.log('Dashboard user', user, companyData, companyUsersArray)
	//console.log('Dashboard', components, companyProcesses, user.pinned_modules, selectedComponent)

	return (
		<>
			<div className={cls.host} style={{ display: companyData.status === 'inactive' ? 'none' : '' }}>

				<div className={cls.dashboardPanel} style={{ display: 'flex', margin: '80px 0 0 0' }}>
					<div style={{ marginLeft: 'auto', marginRight: '0', display: (allModules?.length == 0 || companyProcesses.length == 0 || companyProcesses.filter(pr => pr?.steps?.length == 0).length > 0) ? '' : 'none' }}>
						<Button light icon={<FontAwesomeIcon icon={faRetweet} />} style={{ width: '50px' }}
							clicked={() => {
								setLoading(true);
								getCompanyProcesses(APPEND_TO_DATA, FORCED)
									.pipe(take(1))
									.subscribe({
										complete: () => getAllModules(APPEND_TO_DATA, FORCED).pipe(take(1)).subscribe({
											next: () => setLoading(false)
										}),
									});
							}}
						/>

					</div>

					{!isMobile && searchButton()}
					{!isMobile && (
						<TaskBoardPanel style={{ display: aiResponse?.candidates?.length > 0 ? '' : 'none', marginTop: '20px', width: '70%' }} cardTitle={'Search Results:'}>
							{aiResults}
							<Button
								lighter
								style={{ width: '120px' }}
								title={'Clear'}
								clicked={() => {
									setAIResponse({ candidates: [] });
									setSearchQuery('');
								}}
							/>
						</TaskBoardPanel>
					)}
					{!isMobile ? <HeaderTopBar headerTitle={`Dashboard`} hasHeaderImgX headerImgSrc={tasks} targetProcessing={false} /> : <div className={cls.searchInput}> {'Dashboard'} </div>}
					{renderProcessDashboardFunction()}

					{user?.pinned_modules?.length > 0 &&
						R.sortWith([R.descend(R.prop('name'))])(user?.pinned_modules ?? []).map((pinned_module, index) => {
							const proc = companyProcesses.find(proc => proc.id === pinned_module?.procedure?.id);
							return (
								<div key={index}>
									<div style={{ minWidth: isMobile ? '110%' : '600px', marginBottom: '20px', width: isMobile ? '100%' : '70%' }}>
										<ModulePanel
											cardTitle={pinned_module.name}
											withAddButton={!pinned_module.options?.asGraphical ?? proc ? (proc?.steps.length > 0 ? (companyData.status === 'trial_ended' || companyData.status === 'inactive' ? false : true) : false) : false}
											onAddItem={() => {
												companyData.start = false;
												getCompanyDetails().pipe(first()).subscribe({});
												store.dispatch(setShowMenu(false));
												store.dispatch(
													setProcessModule({
														...pinned_module.procedure,
														stepIndex: 1,
														module_id: pinned_module.id,
														module: pinned_module,
													})
												);
												setTaskProcessContext({
													action: processTaskAction.setModuleItems,
													value: selectedComponent.component_items,
												});

												setTaskProcessContext({
													action: processTaskAction.setModuleNewStepComponents,
													value: [],
												});
												setTaskProcessContext({
													action: processTaskAction.setComponents,
													value: [],
												});

												//clear all values
												begunModule?.processModule?.steps?.length > 0 && begunModule?.processModule?.steps?.filter(step => step?.component_blueprints?.filter(cb => cb.selected_fields.filter(field => (field.value = undefined))));

												navigate('/begin-module');
											}}
											loading={loading}
											endLabel={isMobile ? '' : pinned_module.options?.asGraphical === true ? '' : 'Created Date'}
										>
											{renderModulesFunction(pinned_module)}
										</ModulePanel>
									</div>
									<ModalR onClose={() => setOpenDetailView(false)} hasCloseIcon={isMobile ? true : selectedComponent?.component_fields?.length == 0 ? true:  false} blured={true} scrollable={true} isOpen={openDetailView} backdropColor={true} shadowedContainerStyle={{ width: isMobile ? '100%' : '800px' }}>
										<RenderComponentDetailView print={forPrinting} ref={componentRef} begunModule={begunModule} allModules={allModules} companyData={companyData} components={components} selectedComponent={selectedComponent} companyUsersArray={companyUsersArray} />
										{selectedComponent?.component_fields?.length > 0 && <div className={cls.emulatedFlexGap} style={{ width: isMobile ? '100%' : '' }}>
											{!forPrinting && (
												<Button
													title={'Close'}
													style={{ width: isMobile ? '90%' : '120px' }}
													clicked={() => {
														setSelectedComponent({});
														setOpenDetailView(false);
														setForPrinting(false);
														store.dispatch(setProcessModule(''));
													}}
												/>
											)}
											{/* Action Buttons */}

											{((status === undefined && authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0) ||
												// ((status === undefined || status === 'New' || status === 'Show') && selectedComponent?.created_by?.id === user?.id) ||
												(status !== undefined &&
													!(status === 'Hide' || status === 'Closed' || status === companyData?.misc_info?.lock) &&
													authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0 &&
													(begunModule?.processModule?.module?.options?.strict != true || selectedComponent?.created_by?.id !== user?.id))) &&
												(selectedComponent.created_by !== user?.id) &&

												begunModule?.processModule?.steps[0].component_blueprints.find(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Action Button').length > 0)?.selected_fields.filter(sf => sf.data_type_name === 'Action Button').map((sf, index) => {
													return <Button key={index} title={sf.field_name} loading={loading} clicked={() => {

														if (sf.options.action === 'user') {
															setLoading(true);

															addNewFieldToComponent({
																component_id: selectedComponent.id,
																index: sf.index,
																group: 99,
																value: user.id,
																procedure_step_blueprint_field_id: sf.procedure_step_blueprint_field_id
															}).subscribe({
																next: data => {
																	setLoading(false);
																	setOpenDetailView(false)
																},
																error: () => { },
																complete: () => { }
															})


														} else if (sf.options.action === 'status') {
															console.log('status')
														} else if (sf.options.action === 'date') {
															console.log('date')
														} else if (sf.options.action === 'value') {
															console.log('value')
														} else {
															console.log('any')
														}
													}}
														style={{ backgroundColor: 'green', color: 'white', width: isMobile ? '90%' : '120px', display: (sf.options.action === 'user' && selectedComponent.component_fields?.find(cf => cf.procedure_step_blueprint_field_id === sf.procedure_step_blueprint_field_id)?.value) ? 'none' : '' }}
													/>

												})}
											{forPrinting && (
												<Button
													light
													title={'Close'}
													style={{ width: isMobile ? '90%' : '120px' }}
													clicked={() => {
														setForPrinting(false);
													}}
												/>
											)}

											{((status === undefined && (user?.id === begunModule?.processModule?.user_id || authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0)) ||
												((status === undefined || status === 'New') && selectedComponent?.created_by?.id === user?.id) ||
												(status !== undefined &&
													!(status === 'Closed' || status === companyData?.misc_info?.lock) &&
													authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0 &&
													(user?.pinned_modules?.find(mod => mod.id === selectedComponent.module_id)?.options?.strict != true || selectedComponent?.created_by?.id !== user?.id)) ||
												(selectedComponent?.is_complete === false && selectedComponent?.created_by?.id === user?.id)

											) && (
													<Button
														light
														title={'Edit'}
														style={{
															backgroundColor: isMobile ? 'var(--app-color-blue)' : '', color: isMobile ? 'white' : '',
															width: isMobile ? '90%' : '120px', display: selectedComponent.component_fields?.filter(cf => (cf.data_type_name === 'Action Button' && cf.options.action === 'user')).length === 0 ? '' :
																selectedComponent.component_fields?.filter(cf => (cf.data_type_name === 'Action Button' && cf.options.action === 'user' && cf.value === undefined)).length === 0 ?
																	selectedComponent.component_fields?.filter(cf => (cf.data_type_name === 'Action Button' && cf.options.action === 'user' && cf.value === user?.id)).length > 0 ? '' : 'none' : 'none'
														}}
														clicked={() => {
															let component_array = [];
															begunModule?.processModule?.steps?.length > 0 && begunModule?.processModule?.steps?.filter(step => step?.component_blueprints?.filter(cb => cb.selected_fields.filter(field => (field.value = undefined))));
															R.uniqWith(R.eqProps('group'))(selectedComponent.component_fields).map(f => {
																component_array = [...component_array, { id: f.component_blueprint_id, temp_id: f.id, selected_fields: R.filter(R.propEq('group', f.group))(selectedComponent.component_fields) }];
															});

															begunModule.processModule.steps.filter(step => {
																step.component_blueprints.filter(cb => {
																	cb.selected_fields.filter(sf => {
																		const field_found = selectedComponent.component_fields?.find(cf => cf.field_name === sf.field_name);
																		if (field_found != undefined) {
																			sf.value = field_found.value;
																		} else if (sf.data_type_name === 'Record') {
																			const label_found = selectedComponent.component_fields?.find(cf => cf.field_name === sf.options.name);
																			if (label_found != undefined) {
																				sf.value = label_found.value;
																			}
																		}
																	});
																});
															});

															setTaskProcessContext({
																action: processTaskAction.setComponents,
																value: component_array,
															});
															setTaskProcessContext({
																action: processTaskAction.setModuleItems,
																value: JSON.parse(JSON.stringify(selectedComponent.component_items)),
															});
															store.dispatch(setShowMenu(false));

															const steps_for_use = begunModule.processModule.steps
																.filter(step => step?.options?.showStepAll == undefined || step?.options?.showStepAll == true || (step?.options?.showStepAll == false && step?.options?.showOnly?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0))
																.map((step, i) => {
																	return { ...step, rank: i + 1 };
																});

															store.dispatch(
																setProcessModule({
																	...begunModule.processModule,
																	steps: steps_for_use,
																	stepIndex: 1,
																	back_id: steps_for_use.length > 0 ? steps_for_use[0].id : 0,
																	module_id: selectedComponent.module_id,
																	module: allModules?.find(mod => mod.id === selectedComponent.module_id),
																	isUpdating: true,
																	selectedComponent: selectedComponent,
																})
															);

															navigate('/begin-module');
														}}
													/>
												)}
											{!forPrinting && !isMobile && <Button light title={'Print'} clicked={() => setForPrinting(true)} style={{ width: '120px' }} />}
											{forPrinting && <ReactToPrint trigger={() => <button className={cls.singleButton}>Send to Printer</button>} content={() => componentRef.current} />}



										</div>}
									</ModalR>
								</div>
							);
						})}

					<div style={{ display: user?.ui_permissions?.find(permis => permis === 'view-dashboard-task') ? '' : 'none' }}>
						<div className={cls.headerContainer} style={{ display: '' }}>
							<div style={{ paddingRight: '30px' }}>
								<Button className={allModules.length > 1 ? cls.newTaskButton : cls.default} style={{ width: '120px' }} clicked={newTaskOpen} title={'New Task'} />
							</div>
						</div>

						<Tabs
							style={{ width: '100%', fontFamily: 'var(--app-text-main-font)', fontSize: isMobile ? '12px' : '16px', fontWeight: '700' }}
							selectedIndex={tabIndex}
							onSelect={index => {
								setTabIndex(index);
								setPage(1);
							}}
						>
							<TabList>
								<Tab>
									{'Today'}
									{renderTasks?.todayTasks.length > 0 && ` [${renderTasks?.todayTasks.length}]`}
								</Tab>
								<Tab>
									{'Overdue'}
									{renderTasks?.overdueTasks.length > 0 && ` [${renderTasks?.overdueTasks.length}]`}
								</Tab>
								<Tab>
									{'Upcoming'}
									{renderTasks?.laterTasks.length > 0 && ` [${renderTasks?.laterTasks.length}]`}
								</Tab>
								<Tab>{'Completed'}</Tab>
							</TabList>

							<TabPanel>
								<div style={{ minWidth: isMobile ? '110%' : '600px', marginTop: '20px', width: isMobile ? '100%' : '70%' }}>
									<TaskBoardPanel cardTitle={'Tasks for Today'}>{renderTasksFunction(renderTasks.todayTasks)}</TaskBoardPanel>
								</div>
							</TabPanel>
							<TabPanel>
								<div style={{ minWidth: isMobile ? '110%' : '600px', marginTop: '20px', width: isMobile ? '100%' : '70%' }}>
									<TaskBoardPanel cardTitle={'Overdue Tasks'}>{renderTasksFunction(renderTasks.overdueTasks)}</TaskBoardPanel>
								</div>
							</TabPanel>

							<TabPanel>
								<div style={{ minWidth: isMobile ? '110%' : '600px', marginTop: '20px', width: isMobile ? '100%' : '70%' }}>
									<TaskBoardPanel cardTitle={'Upcoming Tasks'}>{renderTasksFunction(renderTasks.laterTasks)}</TaskBoardPanel>
								</div>
							</TabPanel>
							<TabPanel>
								<div style={{ minWidth: isMobile ? '110%' : '600px', marginTop: '20px', width: isMobile ? '100%' : '70%' }}>
									<TaskBoardPanel cardTitle={'Completed Tasks'}>{renderCompletedTasksFunction(renderTasks.completedTasks)}</TaskBoardPanel>
								</div>
							</TabPanel>
							<br />
						</Tabs>
					</div>
					<div style={{ marginTop: '20px', width: isMobile ? '120%' : '50%', display: user.user_type === 'superadmin' ? '' : 'none' }}>
						<div className={cls.headerContainer} style={{ display: '' }}>
							<div style={{ paddingRight: '30px' }}>
								<Button style={{ width: '150px' }} clicked={createCompany} title={'New Company'} loading={loading} icon={<img alt="" src={taskIcon} style={{ width: '24px', height: '24px', display: 'none' }} />} />
							</div>
						</div>
						{newCompany?.message !== '' && <MessageContainer message={newCompany?.message} onClick={() => setNewCompany({ ...newCompany, message: '' })} />}
						<TaskBoardPanel cardTitle={'Create Company'}>{renderSuperAdminCreateCompany()}</TaskBoardPanel>
					</div>
				</div>
			</div>

			<ModalR onClose={() => { }} hasCloseIcon={isMobile ? true : false} blured={true} scrollable={true} isOpen={isMobile ? false : showInfo} backdropColor={true} shadowedContainerStyle={{ width: '90%', minWidth: '600px' }}>
				<div style={{ display: 'flex', flexDirection: 'column', margin: 'auto', padding: '100px', fontFamily: 'var(--app-text-main-font)' }}>
					<img alt="" src={companyData?.company_standards?.banner} style={{ height: '500px', margin: 'auto', objectFit: 'contain' }} />

					<div className={cls.modalTitle}>
						<p>
							{companyData?.company_standards?.welcome ?? `Welcome to ${companyData.display_name}`}
						</p>
					</div>
					<p>
						{companyData?.company_standards?.message ??
							'This application is being run in FlowHero. This is our cloud solution designed to automate the various workflows of your company.'}
					</p>
					<p>
						{companyData?.company_standards?.subMessage ??
							'Workflows are the steps undertaken to complete a task and give a result. In Flowhero, workflows becomes the basis of a module. Think of modules as a page wizard that uses workflows as the undelying steps for the module and the transaction record it will bring out when the module is accessed, inputs fed and saved.'}
					</p>
					<Button disabled={allModules?.length > 0 ? false: true }title={"Let's start"} clicked={() => setShowInfo(false)} />
					<div style={{ float: 'right', width: '380px', marginTop: '50px' }}>
						<RenderYesNoSwitcher
							title={'Do not show this screen next time?'}
							style={{ margin: '20px 0px 20px 0px', width: 'auto' }}
							value={!showInfo}
							toggleSelected={val => {
								localStorage.setItem('showInfo', !val)
								setTimeout(()=>setShowInfo(false),10000);
							}}
						/>
					</div>
				</div>
			</ModalR>
			<TaskModal
				modalVisible={taskModalVisible}
				heading={isEditTask ? `Edit Task` : 'Create a New Task'}
				task={isEditTask ? taskToEdit : {}}
				isProcess={false}
				blured={true}
				shadowedContainerStyle={{ width: '35%', minWidth: '400px' }}
				onClose={() => editTaskClose()}
				isEdit={isEditTask}
			/>
			<InfoTaskModal openedTask={taskToEdit} taskName={taskToEdit.name} modalVisible={showTask} modalClosed={() => setShowTask(false)} hasTutorial={false} blured={true} childrenWrapperStyle={{ alignItems: 'center' }} onCancel={() => setShowTask(false)} />
		</>
	);
};
const mapStateToProps = store => {
	const { begunModule, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyProcesses, allModules, components, companyData, companyUsersArray, blueprints } = store.flowReducer;
	const { user } = store.sessionReducer;

	return { begunModule, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyProcesses, allModules, components, companyData, companyUsersArray, user, blueprints };
};

const mapDispatchToProps = dispatch => {
	return {
		onSetSelectedProcess: process => dispatch(setSelectedProcess(process)),
	};
};

export default connect(mapStateToProps, mapDispatchToProps)(Dashboard);
